import{_ as a,o as i,c as n,ag as t}from"./chunks/framework.DXGyWiRo.js";const y=JSON.parse('{"title":"Frontend Dependency Policy","description":"","frontmatter":{},"headers":[],"relativePath":"frontend-dependency-policy.md","filePath":"frontend-dependency-policy.md","lastUpdated":1775910991000}'),l={name:"frontend-dependency-policy.md"};function o(d,e,s,r,c,p){return i(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="frontend-dependency-policy" tabindex="-1">Frontend Dependency Policy <a class="header-anchor" href="#frontend-dependency-policy" aria-label="Permalink to &quot;Frontend Dependency Policy&quot;">​</a></h1><p>This document defines the approved supply-chain policy for the Vue frontend in <code>rustchat</code>.</p><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h2><ol><li>keep the direct dependency surface small</li><li>make installs deterministic</li><li>stop untrusted install-time code from running automatically in CI</li><li>make dependency changes visible and reviewable</li><li>support emergency transitive remediation without waiting on upstream</li></ol><h2 id="standard-package-manager" tabindex="-1">Standard Package Manager <a class="header-anchor" href="#standard-package-manager" aria-label="Permalink to &quot;Standard Package Manager&quot;">​</a></h2><p>The frontend uses <strong>npm</strong> as the only supported package manager.</p><p>Rules:</p><ol><li><code>frontend/package-lock.json</code> is the single lockfile source of truth.</li><li><code>frontend/pnpm-lock.yaml</code> and <code>frontend/yarn.lock</code> are not allowed.</li><li>Routine local setup uses <code>npm ci</code>.</li><li>CI and release-oriented builds use <code>npm ci --ignore-scripts</code>.</li><li>Use <code>npm install</code> or <code>npm uninstall</code> only when you are intentionally changing dependencies and plan to review the resulting manifest and lockfile diff.</li></ol><h2 id="approved-dependency-categories" tabindex="-1">Approved Dependency Categories <a class="header-anchor" href="#approved-dependency-categories" aria-label="Permalink to &quot;Approved Dependency Categories&quot;">​</a></h2><p>Every direct dependency must be justified in <code>frontend/dependency-policy.json</code> under exactly one of these categories:</p><ol><li><code>framework-critical</code></li><li><code>build-tool-critical</code></li><li><code>security-critical</code></li><li><code>editor-format-tooling-critical</code></li><li><code>impossible-to-replace-economically</code></li></ol><p>A dependency is not approved merely because it is popular or convenient.</p><h2 id="adding-a-direct-dependency" tabindex="-1">Adding a Direct Dependency <a class="header-anchor" href="#adding-a-direct-dependency" aria-label="Permalink to &quot;Adding a Direct Dependency&quot;">​</a></h2><p>Before adding a new frontend dependency:</p><ol><li>verify that browser APIs, existing internal utilities, or current packages cannot solve the problem cheaply</li><li>document the dependency in <code>frontend/dependency-policy.json</code></li><li>choose one approved category</li><li>add a short reason that explains why the package exists</li><li>include the dependency change in PR notes</li></ol><p>Frontend dependency PRs must include:</p><ol><li>the problem being solved</li><li>why existing code or platform APIs were insufficient</li><li>the chosen category and rationale</li><li>whether the package introduces lifecycle scripts, native code, browser binaries, or external network behavior</li></ol><h2 id="removing-a-dependency" tabindex="-1">Removing a Dependency <a class="header-anchor" href="#removing-a-dependency" aria-label="Permalink to &quot;Removing a Dependency&quot;">​</a></h2><p>Dependency removal is preferred whenever a package becomes:</p><ol><li>unused</li><li>replaceable with existing platform APIs</li><li>duplicated by another dependency already in the repo</li><li>obsolete after a refactor</li></ol><p>When removing a dependency:</p><ol><li>delete its source usage</li><li>remove it from <code>frontend/package.json</code></li><li>update <code>frontend/package-lock.json</code></li><li>remove its entry from <code>frontend/dependency-policy.json</code></li></ol><h2 id="install-policy" tabindex="-1">Install Policy <a class="header-anchor" href="#install-policy" aria-label="Permalink to &quot;Install Policy&quot;">​</a></h2><h3 id="local-development" tabindex="-1">Local development <a class="header-anchor" href="#local-development" aria-label="Permalink to &quot;Local development&quot;">​</a></h3><p>Use:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> frontend</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ci</span></span></code></pre></div><h3 id="ci-and-release-oriented-builds" tabindex="-1">CI and release-oriented builds <a class="header-anchor" href="#ci-and-release-oriented-builds" aria-label="Permalink to &quot;CI and release-oriented builds&quot;">​</a></h3><p>Use:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> frontend</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ci</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ignore-scripts</span></span></code></pre></div><p>Lifecycle scripts are blocked in CI by default.</p><p>If a tool requires additional setup in CI, that setup must happen as an explicit trusted step after dependency installation.</p><p>Example:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playwright</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chromium</span></span></code></pre></div><h2 id="dependency-review-and-vulnerability-gates" tabindex="-1">Dependency Review and Vulnerability Gates <a class="header-anchor" href="#dependency-review-and-vulnerability-gates" aria-label="Permalink to &quot;Dependency Review and Vulnerability Gates&quot;">​</a></h2><p>Frontend dependency changes are enforced by:</p><ol><li>GitHub dependency review on pull requests</li><li><code>frontend/scripts/check-dependency-policy.mjs</code></li><li><code>npm audit --audit-level=high</code></li></ol><p>These checks must stay green before merge.</p><h2 id="overrides-first-line-transitive-remediation" tabindex="-1">Overrides: First-Line Transitive Remediation <a class="header-anchor" href="#overrides-first-line-transitive-remediation" aria-label="Permalink to &quot;Overrides: First-Line Transitive Remediation&quot;">​</a></h2><p>Use <code>frontend/package.json</code> <code>overrides</code> when a vulnerable transitive dependency can be fixed by forcing a safer version.</p><p>Requirements:</p><ol><li>add or update the override in <code>frontend/package.json</code></li><li>document it in <code>frontend/dependency-policy.json</code></li><li>explain why it exists</li><li>record how to know when it can be removed</li></ol><p>Use overrides first because they are the smallest and least surprising mitigation path.</p><h2 id="patches-fallback-when-overrides-are-not-enough" tabindex="-1">Patches: Fallback When Overrides Are Not Enough <a class="header-anchor" href="#patches-fallback-when-overrides-are-not-enough" aria-label="Permalink to &quot;Patches: Fallback When Overrides Are Not Enough&quot;">​</a></h2><p>If an override cannot remediate the issue, use the repo-managed patch workflow.</p><p>Artifacts:</p><ol><li>patch files live in <code>frontend/patches/</code></li><li>patch metadata lives in <code>frontend/dependency-patches.json</code></li><li>patches are applied by <code>frontend/scripts/apply-dependency-patches.mjs</code></li></ol><p>Each patch entry must include:</p><ol><li>package name</li><li>patch file path</li><li>reason</li><li>removal condition</li></ol><p>Patch policy:</p><ol><li>patches are emergency or short-lived controls, not permanent forks by default</li><li>each patch must have a clear retirement path</li><li>if upstream publishes a safe fix, remove the patch and prefer a normal versioned dependency update</li></ol><h2 id="install-script-exceptions" tabindex="-1">Install Script Exceptions <a class="header-anchor" href="#install-script-exceptions" aria-label="Permalink to &quot;Install Script Exceptions&quot;">​</a></h2><p>Default policy:</p><ol><li>no dependency lifecycle scripts run in CI</li><li>no silent exceptions are allowed</li></ol><p>If an exception becomes necessary, document all of the following in the PR and policy metadata:</p><ol><li>why the package is required</li><li>what risk the script introduces</li><li>why it cannot be replaced</li><li>whether it is build-only or runtime-critical</li><li>how CI invokes it explicitly</li></ol><h2 id="update-strategy" tabindex="-1">Update Strategy <a class="header-anchor" href="#update-strategy" aria-label="Permalink to &quot;Update Strategy&quot;">​</a></h2><p>Frontend dependency updates are PR-based and reviewable.</p><p>Rules:</p><ol><li>Dependabot may open frontend update PRs.</li><li>Major updates must not auto-merge.</li><li>Security updates are reviewed separately from routine feature/tooling upgrades.</li><li>Every dependency update must still pass frontend tests, build, and policy gates.</li></ol><h2 id="dependency-inventory" tabindex="-1">Dependency Inventory <a class="header-anchor" href="#dependency-inventory" aria-label="Permalink to &quot;Dependency Inventory&quot;">​</a></h2><p>Frontend CI publishes a machine-readable dependency inventory artifact using npm&#39;s resolved dependency tree.</p><p>Reviewers should be able to answer:</p><ol><li>what changed</li><li>why the dependency exists</li><li>whether install-time code ran</li><li>whether a transitive dependency is pinned or patched centrally</li></ol><h2 id="pr-checklist-for-dependency-changes" tabindex="-1">PR Checklist for Dependency Changes <a class="header-anchor" href="#pr-checklist-for-dependency-changes" aria-label="Permalink to &quot;PR Checklist for Dependency Changes&quot;">​</a></h2><p>If your PR changes <code>frontend/package.json</code> or <code>frontend/package-lock.json</code>, make sure it also includes:</p><ol><li>updates to <code>frontend/dependency-policy.json</code></li><li>override metadata if <code>overrides</code> changed</li><li>patch metadata if <code>frontend/dependency-patches.json</code> changed</li><li>a short explanation in the PR body</li><li>proof that the frontend dependency checks still pass</li></ol>`,66)])])}const u=a(l,[["render",o]]);export{y as __pageData,u as default};
